mapper.select:
select * from nx_ocr_task


		and nx_ocr_task_upload_user_id = #{nxOcrTaskUploadUserId}


		and nx_ocr_task_processor_user_id = #{nxOcrTaskProcessorUserId}


		and nx_ocr_task_status = #{nxOcrTaskStatus}


		and nx_ocr_task_distributer_id = #{nxOcrTaskDistributerId}


		and nx_ocr_task_department_id = #{nxOcrTaskDepartmentId}


		and nx_ocr_task_department_father_id = #{nxOcrTaskDepartmentFatherId}




		order by ${sidx} ${order}


		order by nx_ocr_task_id desc



	limit #{offset}, #{limit}

select count(*) from nx_ocr_task


		and nx_ocr_task_upload_user_id = #{nxOcrTaskUploadUserId}


		and nx_ocr_task_processor_user_id = #{nxOcrTaskProcessorUserId}


		and nx_ocr_task_status = #{nxOcrTaskStatus}


		and nx_ocr_task_distributer_id = #{nxOcrTaskDistributerId}


		and nx_ocr_task_department_id = #{nxOcrTaskDepartmentId}


		and nx_ocr_task_department_father_id = #{nxOcrTaskDepartmentFatherId}

select * from nx_ocr_task


		and nx_ocr_task_upload_user_id = #{nxOcrTaskUploadUserId}


		and nx_ocr_task_processor_user_id = #{nxOcrTaskProcessorUserId}


		and nx_ocr_task_status = #{nxOcrTaskStatus}


		and nx_ocr_task_distributer_id = #{nxOcrTaskDistributerId}


		and nx_ocr_task_department_id = #{nxOcrTaskDepartmentId}


		and nx_ocr_task_department_father_id = #{nxOcrTaskDepartmentFatherId}


order by nx_ocr_task_id desc

select task.*, dep.nx_department_name as nx_ocr_task_department_name from nx_ocr_task as task
left join nx_department as dep on dep.nx_department_id = task.nx_ocr_task_department_id


		and nx_ocr_task_distributer_id = #{disId}


		and nx_ocr_task_department_father_id = #{departmentFatherId}


		and nx_ocr_task_department_id = #{departmentId}


		and nx_ocr_task_status = #{status}


		and nx_ocr_task_type = #{type}


		and nx_ocr_task_status < #{xiaoyuStatus}




order by nx_ocr_task_id desc

	limit #{offset}, #{limit}

select count(*) from nx_ocr_task


		and nx_ocr_task_distributer_id = #{disId}


		and nx_ocr_task_department_father_id = #{departmentFatherId}


		and nx_ocr_task_department_id = #{departmentId}


		and nx_ocr_task_status = #{status}


		and nx_ocr_task_type = #{type}


		and DATE(nx_ocr_task_create_date) = #{date}


		and nx_ocr_task_status < #{xiaoyuStatus}

select DISTINCT dep.*,
(select count(*) from nx_ocr_task as t where t.nx_ocr_task_department_father_id = dep.nx_department_id

		and t.nx_ocr_task_distributer_id = #{disId}


		and t.nx_ocr_task_status < #{xiaoyuStatus}

) as task_count
from nx_ocr_task as task
left join nx_department as dep on dep.nx_department_id = task.nx_ocr_task_department_father_id



		and task.nx_ocr_task_distributer_id = #{disId}


		and task.nx_ocr_task_status < #{xiaoyuStatus}

	and dep.nx_department_id is not null

order by dep.nx_department_id
